class Solution:
    def gcdOfStrings(self, str1: str, str2: str) -> str:
        if str1 + str2 != str2 + str1:
            return ""
        def gcd(a, b):
            if b == 0:
                return a
            return gcd(b, a % b)
        g = gcd(len(str1), len(str2))
        return str1[:g]
